import functools
import warnings

def deprecated(reason):
    """
    Bu bir işlevi veya sınıfı kullanımdan kaldırmak için bir dekoratördür.

    Kullanım:
    @deprecated("Bunun yerine 'diğer_işlev' kullanın")
    def eski_işlev(x, y):
        return x + y
    """
    if isinstance(reason, str):
        # reason, dekoratör parametresi
        def decorator(func):

            if functools.wraps is not None:
                @functools.wraps(func)
                def new_func(*args, **kwargs):
                    warnings.warn(
                        "{} deprecated. {}".format(func.__name__, reason),
                        category=DeprecationWarning,
                        stacklevel=2
                    )
                    return func(*args, **kwargs)
            else:
                def new_func(*args, **kwargs):
                    warnings.warn(
                        "{} deprecated. {}".format(func.__name__, reason),
                        category=DeprecationWarning,
                        stacklevel=2
                    )
                    return func(*args, **kwargs)

            new_func.__name__ = func.__name__
            new_func.__doc__ = func.__doc__
            new_func.__dict__.update(func.__dict__)
            return new_func

        return decorator

    elif callable(reason):
        # reason, dekore edilecek işlev.
        func = reason

        if functools.wraps is not None:
            @functools.wraps(func)
            def new_func(*args, **kwargs):
                warnings.warn(
                    "{} deprecated.".format(func.__name__),
                    category=DeprecationWarning,
                    stacklevel=2
                )
                return func(*args, **kwargs)
        else:
            def new_func(*args, **kwargs):
                warnings.warn(
                    "{} deprecated.".format(func.__name__),
                    category=DeprecationWarning,
                    stacklevel=2
                )
                return func(*args, **kwargs)


        new_func.__name__ = func.__name__
        new_func.__doc__ = func.__doc__
        new_func.__dict__.update(func.__dict__)
        return new_func

    else:
        raise TypeError(repr(type(reason)))
